import React from 'react';
import styled from 'styled-components';

// Conditional import for Chart.js components with better error handling
let ChartJS, Line, Bar, Pie, CategoryScale, LinearScale, PointElement, LineElement, BarElement, ArcElement, Title, Tooltip, Legend;

try {
  // Try to import Chart.js components
  const chartJSModule = require('chart.js');
  ChartJS = chartJSModule.Chart || chartJSModule.default || chartJSModule;
  CategoryScale = chartJSModule.CategoryScale;
  LinearScale = chartJSModule.LinearScale;
  PointElement = chartJSModule.PointElement;
  LineElement = chartJSModule.LineElement;
  BarElement = chartJSModule.BarElement;
  ArcElement = chartJSModule.ArcElement;
  Title = chartJSModule.Title;
  Tooltip = chartJSModule.Tooltip;
  Legend = chartJSModule.Legend;
  
  const reactChartJS2Module = require('react-chartjs-2');
  Line = reactChartJS2Module.Line;
  Bar = reactChartJS2Module.Bar;
  Pie = reactChartJS2Module.Pie;
  
  // Register Chart.js components if available
  if (ChartJS && ChartJS.register && CategoryScale) {
    ChartJS.register(
      CategoryScale,
      LinearScale,
      PointElement,
      LineElement,
      BarElement,
      ArcElement,
      Title,
      Tooltip,
      Legend
    );
  }
} catch (error) {
  console.warn('Chart.js not available, using fallback UI:', error);
  // Fallback components if Chart.js is not available
  Line = () => <div>Line chart visualization would appear here</div>;
  Bar = () => <div>Bar chart visualization would appear here</div>;
  Pie = () => <div>Pie chart visualization would appear here</div>;
}

const ChartContainer = styled.div`
  background: white;
  border-radius: 1rem;
  padding: 1.5rem;
  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05);
  border: 1px solid #e2e8f0;
  margin: 1rem 0;
`;

const ChartHeader = styled.div`
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 1rem;
`;

const ChartTitle = styled.h3`
  margin: 0;
  color: #1e293b;
  font-size: 1.25rem;
`;

const ChartTypeSelector = styled.div`
  display: flex;
  gap: 0.5rem;
`;

const ChartTypeButton = styled.button`
  padding: 0.5rem 1rem;
  border: 1px solid #cbd5e1;
  background: ${props => props.active ? '#3b82f6' : 'white'};
  color: ${props => props.active ? 'white' : '#64748b'};
  border-radius: 0.5rem;
  cursor: pointer;
  font-size: 0.875rem;
  
  &:hover {
    background: ${props => props.active ? '#2563eb' : '#f1f5f9'};
  }
`;

const InsightsSection = styled.div`
  margin-top: 1.5rem;
  padding-top: 1.5rem;
  border-top: 1px solid #e2e8f0;
`;

const InsightsTitle = styled.h4`
  margin: 0 0 1rem 0;
  color: #1e293b;
  font-size: 1rem;
`;

const InsightsList = styled.ul`
  margin: 0;
  padding-left: 1.5rem;
`;

const InsightItem = styled.li`
  margin-bottom: 0.5rem;
  color: #64748b;
`;

const ChartVisualization = styled.div`
  height: 300px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: #f8fafc;
  border-radius: 0.5rem;
  border: 1px dashed #cbd5e1;
  color: #94a3b8;
  font-size: 1rem;
`;

const AISampleChart = ({ chartConfig, insights, title }) => {
  const [chartType, setChartType] = React.useState(chartConfig?.type || 'bar');
  
  // Default chart data if none provided
  const defaultData = {
    labels: ['January', 'February', 'March', 'April', 'May', 'June'],
    datasets: [
      {
        label: 'Sample Data',
        data: [12, 19, 3, 5, 2, 3],
        backgroundColor: 'rgba(59, 130, 246, 0.5)',
        borderColor: 'rgba(59, 130, 246, 1)',
        borderWidth: 1,
      },
    ],
  };
  
  // Default options
  const defaultOptions = {
    responsive: true,
    plugins: {
      legend: {
        position: 'top',
      },
      title: {
        display: true,
        text: title || 'AI-Generated Chart',
      },
    },
  };
  
  // Use provided config or defaults
  const data = chartConfig?.data || defaultData;
  const options = chartConfig?.options || defaultOptions;
  
  // Function to render the appropriate chart based on type
  const renderChart = () => {
    // If Chart.js is not available, show fallback message
    if (typeof Line !== 'function' || typeof Bar !== 'function' || typeof Pie !== 'function') {
      return (
        <ChartVisualization>
          <div>
            <div>Chart visualization would appear here</div>
            <div style={{ fontSize: '0.875rem', marginTop: '0.5rem' }}>
              (Install chart.js and react-chartjs-2 to see charts)
            </div>
          </div>
        </ChartVisualization>
      );
    }
    
    switch (chartType) {
      case 'line':
        return <Line data={data} options={options} />;
      case 'pie':
        return <Pie data={data} options={options} />;
      case 'bar':
      default:
        return <Bar data={data} options={options} />;
    }
  };

  return (
    <ChartContainer>
      <ChartHeader>
        <ChartTitle>{title || 'AI-Generated Data Visualization'}</ChartTitle>
        <ChartTypeSelector>
          <ChartTypeButton 
            active={chartType === 'bar'} 
            onClick={() => setChartType('bar')}
          >
            Bar
          </ChartTypeButton>
          <ChartTypeButton 
            active={chartType === 'line'} 
            onClick={() => setChartType('line')}
          >
            Line
          </ChartTypeButton>
          <ChartTypeButton 
            active={chartType === 'pie'} 
            onClick={() => setChartType('pie')}
          >
            Pie
          </ChartTypeButton>
        </ChartTypeSelector>
      </ChartHeader>
      
      <div style={{ height: '300px' }}>
        {renderChart()}
      </div>
      
      {insights && insights.length > 0 && (
        <InsightsSection>
          <InsightsTitle>Data Insights</InsightsTitle>
          <InsightsList>
            {insights.map((insight, index) => (
              <InsightItem key={index}>{insight}</InsightItem>
            ))}
          </InsightsList>
        </InsightsSection>
      )}
    </ChartContainer>
  );
};

export default AISampleChart;
